import{_ as t,c as s,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"Context Compression: Long Session Stability | Antigravity-Manager","description":"Learn Antigravity-Manager's context compression mechanism to reduce 400 signature errors and improve long session stability with three-tier progressive processing.","frontmatter":{"title":"Context Compression: Long Session Stability | Antigravity-Manager","sidebarTitle":"Context Compression","subtitle":"Context Compression: Long Session Stability","description":"Learn Antigravity-Manager's context compression mechanism to reduce 400 signature errors and improve long session stability with three-tier progressive processing.","tags":["Context Compression","Signature Caching","Thinking","Tool Result","Stability"],"prerequisite":["start-proxy-and-first-client","advanced-monitoring"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/advanced/context-compression/index.md","filePath":"lbjlaq/Antigravity-Manager/advanced/context-compression/index.md"}`),r={name:"lbjlaq/Antigravity-Manager/advanced/context-compression/index.md"};function a(n,e,l,d,c,h){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="long-session-stability-context-compression-signature-caching-and-tool-result-compression" tabindex="-1">Long Session Stability: Context Compression, Signature Caching, and Tool Result Compression <a class="header-anchor" href="#long-session-stability-context-compression-signature-caching-and-tool-result-compression" aria-label="Permalink to &quot;Long Session Stability: Context Compression, Signature Caching, and Tool Result Compression&quot;">​</a></h1><p>When running long sessions with Claude Code or Cherry Studio, the most frustrating issue isn&#39;t that the model isn&#39;t smart enough—it&#39;s that the conversation suddenly starts throwing errors: <code>Prompt is too long</code>, 400 signature errors, broken tool call chains, or tool loops that get progressively slower.</p><p>This lesson covers three things Antigravity Tools does to solve these problems: context compression (three tiers of progressive intervention), signature caching (keeping Thinking&#39;s signature chain intact), and tool result compression (preventing tool output from overwhelming context).</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Explain what each tier of progressive context compression does and their respective trade-offs</li><li>Know what&#39;s stored in the three-layer signature cache (Tool/Family/Session) and the impact of 2-hour TTL</li><li>Understand tool result compression rules: when base64 images get dropped, when browser snapshots get turned into head+tail summaries</li><li>When needed, adjust compression trigger timing via <code>proxy.experimental</code> threshold switches</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><ul><li>After long conversations, 400 errors suddenly appear—it looks like signature expiration, but you don&#39;t know where signatures come from or where they&#39;re lost</li><li>Tool calls keep increasing, and historical tool_results stack up until upstream rejects them directly (or becomes extremely slow)</li><li>You want to use compression as a rescue mechanism, but worry about breaking Prompt Cache, affecting consistency, or causing the model to lose information</li></ul><h2 id="when-to-use-this-technique" tabindex="-1">When to Use This Technique <a class="header-anchor" href="#when-to-use-this-technique" aria-label="Permalink to &quot;When to Use This Technique&quot;">​</a></h2><ul><li>You&#39;re running long-chain tool tasks (searching/file reading/browser snapshots/multi-round tool loops)</li><li>You&#39;re using Thinking models for complex reasoning, and sessions often span dozens of rounds</li><li>You&#39;re troubleshooting stability issues that are reproducible on the client side but unclear in root cause</li></ul><h2 id="what-is-context-compression" tabindex="-1">What Is Context Compression <a class="header-anchor" href="#what-is-context-compression" aria-label="Permalink to &quot;What Is Context Compression&quot;">​</a></h2><p><strong>Context compression</strong> is the agent&#39;s automatic noise reduction and size reduction on historical messages when it detects excessive context pressure: first trim old tool rounds, then compress old Thinking text into placeholders while preserving signatures, and finally in extreme cases generate an XML summary and Fork a new session to continue the conversation—thereby reducing failures caused by <code>Prompt is too long</code> and broken signature chains.</p><div class="info custom-block"><p class="custom-block-title">How Is Context Pressure Calculated?</p><p>The Claude processor performs a lightweight estimate using <code>ContextManager::estimate_token_usage()</code>, calibrates with <code>estimation_calibrator</code>, then uses <code>usage_ratio = estimated_usage / context_limit</code> to get the pressure percentage (logs will print raw/calibrated values).</p></div><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><ul><li>You&#39;ve successfully run your local proxy, and the client is actually using the <code>/v1/messages</code> path (see <a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Start Local Proxy and Connect First Client</a>)</li><li>You can view proxy logs (developer debugging or local log files). The test plan in the repository gives an example log path and grep method (see <code>docs/testing/context_compression_test_plan.md</code>)</li></ul><div class="tip custom-block"><p class="custom-block-title">Use Proxy Monitor for Better Localization</p><p>If you want to match compression triggers with specific request types/accounts/tool call rounds, it&#39;s recommended to keep Proxy Monitor open simultaneously.</p></div><h2 id="core-idea" tabindex="-1">Core Idea <a class="header-anchor" href="#core-idea" aria-label="Permalink to &quot;Core Idea&quot;">​</a></h2><p>This stability design doesn&#39;t simply delete all history—instead, it intervenes progressively from lowest to highest cost:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Trigger Point (Configurable)</th><th>What It Does</th><th>Cost/Side Effects</th></tr></thead><tbody><tr><td>Layer 1</td><td><code>proxy.experimental.context_compression_threshold_l1</code> (default 0.4)</td><td>Identify tool rounds, keep only the most recent N rounds (5 in the code), delete tool_use/tool_result pairs from earlier rounds</td><td>Doesn&#39;t modify remaining message content, more Prompt Cache-friendly</td></tr><tr><td>Layer 2</td><td><code>proxy.experimental.context_compression_threshold_l2</code> (default 0.55)</td><td>Compress old Thinking text into <code>&quot;...&quot;</code>, but preserve <code>signature</code>, and protect the most recent 4 messages from modification</td><td>Modifies historical content; comments explicitly note it breaks cache, but can preserve signature chain</td></tr><tr><td>Layer 3</td><td><code>proxy.experimental.context_compression_threshold_l3</code> (default 0.7)</td><td>Call background model to generate XML summary, then Fork a new message sequence to continue conversation</td><td>Depends on background model call; if it fails, returns 400 (with friendly prompt)</td></tr></tbody></table><p>Next, we&#39;ll explain each tier in detail, and cover signature caching and tool result compression together.</p><h3 id="layer-1-tool-round-trimming-trim-tool-messages" tabindex="-1">Layer 1: Tool Round Trimming (Trim Tool Messages) <a class="header-anchor" href="#layer-1-tool-round-trimming-trim-tool-messages" aria-label="Permalink to &quot;Layer 1: Tool Round Trimming (Trim Tool Messages)&quot;">​</a></h3><p>The key point of Layer 1 is to delete entire tool interaction rounds, avoiding context inconsistency from partial deletions.</p><ul><li>One tool interaction round is identified by <code>identify_tool_rounds()</code>: <code>tool_use</code> appearing in <code>assistant</code> starts a round, subsequent <code>tool_result</code> in <code>user</code> is still considered part of this round, until a regular user text ends the round.</li><li>Actual trimming is performed by <code>ContextManager::trim_tool_messages(&amp;mut messages, 5)</code>: when historical tool rounds exceed 5 rounds, delete messages involved in earlier rounds.</li></ul><h3 id="layer-2-thinking-compression-while-preserving-signatures" tabindex="-1">Layer 2: Thinking Compression While Preserving Signatures <a class="header-anchor" href="#layer-2-thinking-compression-while-preserving-signatures" aria-label="Permalink to &quot;Layer 2: Thinking Compression While Preserving Signatures&quot;">​</a></h3><p>Many 400 problems aren&#39;t caused by Thinking being too long, but by Thinking&#39;s signature chain breaking. Layer 2&#39;s strategy is:</p><ul><li>Only process <code>ContentBlock::Thinking { thinking, signature, .. }</code> in <code>assistant</code> messages</li><li>Only compress when <code>signature.is_some()</code> and <code>thinking.len() &gt; 10</code>, directly change <code>thinking</code> to <code>&quot;...&quot;</code></li><li>The most recent <code>protected_last_n = 4</code> messages aren&#39;t compressed (roughly the most recent 2 user/assistant rounds)</li></ul><p>This saves a lot of Tokens while keeping <code>signature</code> in history, avoiding situations where tool chains need to backfill signatures but can&#39;t recover them.</p><h3 id="layer-3-fork-xml-summary-ultimate-fallback" tabindex="-1">Layer 3: Fork + XML Summary (Ultimate Fallback) <a class="header-anchor" href="#layer-3-fork-xml-summary-ultimate-fallback" aria-label="Permalink to &quot;Layer 3: Fork + XML Summary (Ultimate Fallback)&quot;">​</a></h3><p>When pressure continues to rise, the Claude processor attempts to restart the session without losing key information:</p><ol><li>Extract the last valid Thinking signature from original messages (<code>ContextManager::extract_last_valid_signature()</code>)</li><li>Concatenate the entire history + <code>CONTEXT_SUMMARY_PROMPT</code> into a request for XML summary generation, model fixed as <code>BACKGROUND_MODEL_LITE</code> (currently <code>gemini-2.5-flash</code>)</li><li>The summary must contain <code>&lt;latest_thinking_signature&gt;</code> for subsequent signature chain continuation</li><li>Fork a new message sequence: <ul><li><code>User: Context has been compressed... + XML summary</code></li><li><code>Assistant: I have reviewed...</code></li><li>Then append the original request&#39;s last user message (if it&#39;s not just the summary instruction)</li></ul></li></ol><p>If Fork + summary fails, it directly returns <code>StatusCode::BAD_REQUEST</code>, prompting you to manually handle with <code>/compact</code> or <code>/clear</code> (see the error JSON returned by the handler).</p><h3 id="sidecar-1-three-layer-signature-caching-tool-family-session" tabindex="-1">Sidecar 1: Three-Layer Signature Caching (Tool / Family / Session) <a class="header-anchor" href="#sidecar-1-three-layer-signature-caching-tool-family-session" aria-label="Permalink to &quot;Sidecar 1: Three-Layer Signature Caching (Tool / Family / Session)&quot;">​</a></h3><p>Signature caching is the fuse for context compression, especially when clients trim/discard signature fields.</p><ul><li>TTL: <code>SIGNATURE_TTL = 2 * 60 * 60</code> (2 hours)</li><li>Layer 1: <code>tool_use_id -&gt; signature</code> (tool chain recovery)</li><li>Layer 2: <code>signature -&gt; model family</code> (cross-model compatibility check, preventing Claude signatures from being brought to Gemini family models)</li><li>Layer 3: <code>session_id -&gt; latest signature</code> (session-level isolation, preventing different conversation pollution)</li></ul><p>These three layers of cache are written/read during Claude SSE streaming parsing and request transformation:</p><ul><li>When streaming parsing reaches thinking&#39;s <code>signature</code>, it&#39;s written to Session Cache (and caches family)</li><li>When streaming parsing reaches tool_use&#39;s <code>signature</code>, it&#39;s written to Tool Cache + Session Cache</li><li>When converting Claude tool calls to Gemini <code>functionCall</code>, it prioritizes filling signatures back from Session Cache or Tool Cache</li></ul><h3 id="sidecar-2-tool-result-compression-tool-result-compressor" tabindex="-1">Sidecar 2: Tool Result Compression (Tool Result Compressor) <a class="header-anchor" href="#sidecar-2-tool-result-compression-tool-result-compressor" aria-label="Permalink to &quot;Sidecar 2: Tool Result Compression (Tool Result Compressor)&quot;">​</a></h3><p>Tool results more easily overwhelm context than chat text, so the request transformation phase performs predictable reduction on tool_result.</p><p>Core rules (all in <code>tool_result_compressor.rs</code>):</p><ul><li>Total character limit: <code>MAX_TOOL_RESULT_CHARS = 200_000</code></li><li>base64 image blocks are removed directly (append a prompt text)</li><li>If it detects output saved to file prompts, it extracts key information and uses <code>[tool_result omitted ...]</code> as placeholder</li><li>If it detects browser snapshots (containing features like <code>page snapshot</code> / <code>ref=</code>), it changes to head + tail summary, and notes how many characters were omitted</li><li>If input looks like HTML, it first removes <code>&lt;style&gt;</code>/<code>&lt;script&gt;</code>/base64 segments before truncation</li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-confirm-compression-thresholds-and-default-values" tabindex="-1">Step 1: Confirm Compression Thresholds (and Default Values) <a class="header-anchor" href="#step-1-confirm-compression-thresholds-and-default-values" aria-label="Permalink to &quot;Step 1: Confirm Compression Thresholds (and Default Values)&quot;">​</a></h3><p><strong>Why</strong> Compression trigger points aren&#39;t hardcoded; they come from <code>proxy.experimental.*</code>. You need to know current thresholds first to judge why it intervenes so early/late.</p><p>Default values (Rust side <code>ExperimentalConfig::default()</code>):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;proxy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;experimental&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_signature_cache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_tool_loop_recovery&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_cross_model_checks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enable_usage_scaling&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.55</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;context_compression_threshold_l3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>What you should see</strong>: Your configuration has <code>proxy.experimental</code> (field names match above), and thresholds are ratio values like <code>0.x</code>.</p><div class="warning custom-block"><p class="custom-block-title">Configuration File Location Not Repeated Here</p><p>Configuration file persistence location and whether restart is needed after modification belong to configuration management. Following this tutorial system, prioritize referring to <a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/advanced/config/">Configuration Full Guide: AppConfig/ProxyConfig, Persistence Location &amp; Hot Update Semantics</a>.</p></div><h3 id="step-2-use-logs-to-confirm-whether-layer-1-2-3-are-triggered" tabindex="-1">Step 2: Use Logs to Confirm Whether Layer 1/2/3 Are Triggered <a class="header-anchor" href="#step-2-use-logs-to-confirm-whether-layer-1-2-3-are-triggered" aria-label="Permalink to &quot;Step 2: Use Logs to Confirm Whether Layer 1/2/3 Are Triggered&quot;">​</a></h3><p><strong>Why</strong> All three tiers are internal proxy behaviors; the most reliable verification is seeing if logs contain <code>[Layer-1]</code> / <code>[Layer-2]</code> / <code>[Layer-3]</code>.</p><p>The repository&#39;s test plan provides an example command (adjust to your actual log path as needed):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Application</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Support/com.antigravity.tools/logs/antigravity.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Layer-[123]&quot;</span></span></code></pre></div><p><strong>What you should see</strong>: When pressure increases, logs show records like <code>Tool trimming triggered</code>, <code>Thinking compression triggered</code>, <code>Fork successful</code> (specific fields based on actual log text).</p><h3 id="step-3-understand-the-difference-between-purification-and-compression-don-t-mix-expectations" tabindex="-1">Step 3: Understand the Difference Between Purification and Compression (Don&#39;t Mix Expectations) <a class="header-anchor" href="#step-3-understand-the-difference-between-purification-and-compression-don-t-mix-expectations" aria-label="Permalink to &quot;Step 3: Understand the Difference Between Purification and Compression (Don&#39;t Mix Expectations)&quot;">​</a></h3><p><strong>Why</strong> Some problems (like forced downgrade to models that don&#39;t support Thinking) need purification rather than compression. Purification directly deletes Thinking blocks; compression preserves the signature chain.</p><p>In the Claude handler, backend task downgrading goes through <code>ContextManager::purify_history(..., PurificationStrategy::Aggressive)</code>, which directly removes historical Thinking blocks.</p><p><strong>What you should see</strong>: You can distinguish two types of behaviors:</p><ul><li>Purification is deleting Thinking blocks</li><li>Layer 2 compression is replacing old Thinking text with <code>&quot;...&quot;</code>, but the signature is still there</li></ul><h3 id="step-4-when-you-encounter-400-signature-errors-first-check-if-session-cache-hit" tabindex="-1">Step 4: When You Encounter 400 Signature Errors, First Check if Session Cache Hit <a class="header-anchor" href="#step-4-when-you-encounter-400-signature-errors-first-check-if-session-cache-hit" aria-label="Permalink to &quot;Step 4: When You Encounter 400 Signature Errors, First Check if Session Cache Hit&quot;">​</a></h3><p><strong>Why</strong> The root cause of many 400s isn&#39;t missing signatures, but signatures not following messages. During request transformation, it prioritizes filling signatures from Session Cache.</p><p>Clues (request transformation phase logs will indicate recovering signatures from SESSION/TOOL cache):</p><ul><li><code>[Claude-Request] Recovered signature from SESSION cache ...</code></li><li><code>[Claude-Request] Recovered signature from TOOL cache ...</code></li></ul><p><strong>What you should see</strong>: When client drops signatures but proxy cache still has them, logs show &quot;Recovered signature from ... cache&quot; records.</p><h3 id="step-5-understand-what-tool-result-compression-will-drop" tabindex="-1">Step 5: Understand What Tool Result Compression Will Drop <a class="header-anchor" href="#step-5-understand-what-tool-result-compression-will-drop" aria-label="Permalink to &quot;Step 5: Understand What Tool Result Compression Will Drop&quot;">​</a></h3><p><strong>Why</strong> If you let tools stuff large HTML/browser snapshots/base64 images back into conversation, the proxy will proactively reduce them. You need to know in advance which content will be replaced with placeholders to avoid mistakenly thinking the model didn&#39;t see it.</p><p>Remember three key points:</p><ol><li>base64 images will be removed (changed to prompt text)</li><li>Browser snapshots will become head/tail summaries (with omitted character counts)</li><li>Exceeding 200,000 characters will be truncated and append <code>...[truncated ...]</code> prompt</li></ol><p><strong>What you should see</strong>: In <code>tool_result_compressor.rs</code>, these rules have explicit constants and branches—it&#39;s not empirical deletion.</p><h2 id="checkpoints" tabindex="-1">Checkpoints <a class="header-anchor" href="#checkpoints" aria-label="Permalink to &quot;Checkpoints&quot;">​</a></h2><ul><li>You can clearly explain L1/L2/L3 trigger points come from <code>proxy.experimental.context_compression_threshold_*</code>, defaulting to <code>0.4/0.55/0.7</code></li><li>You can explain why Layer 2 breaks cache: because it modifies historical thinking text content</li><li>You can explain why Layer 3 is called Fork: it transforms conversation into a new sequence of XML summary + confirmation + latest user message</li><li>You can explain that tool result compression will remove base64 images and convert browser snapshots to head/tail summaries</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Possible Cause</th><th>What You Can Do</th></tr></thead><tbody><tr><td>Context feels less stable after Layer 2 triggers</td><td>Layer 2 modifies historical content; comments explicitly note it breaks cache</td><td>If you depend on Prompt Cache consistency, try to let L1 solve problems first, or increase L2 threshold</td></tr><tr><td>Direct 400 returned after Layer 3 triggers</td><td>Fork + summary failed calling background model (network/account/upstream error, etc.)</td><td>First use <code>/compact</code> or <code>/clear</code> per error JSON suggestion; simultaneously check background model call chain</td></tr><tr><td>Images/large content disappear in tool output</td><td>tool_result removes base64 images, truncates oversized output</td><td>Drop important content to local file/link and reference it; don&#39;t expect to stuff 100k lines of text directly back into conversation</td></tr><tr><td>Using Gemini model but it brought Claude signature causing error</td><td>Signatures aren&#39;t cross-model compatible (code has family check)</td><td>Confirm signature source; if needed, let proxy strip historical signatures in retry scenarios (see request transformation logic)</td></tr></tbody></table><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><ul><li>Three-tier compression&#39;s core is cost-graded: first delete old tool rounds, then compress old Thinking, finally Fork + XML summary</li><li>Signature caching is the key to keeping tool chains continuous: Session/Tool/Family three layers each handle one type of problem, TTL is 2 hours</li><li>Tool result compression is a hard limit to prevent tool output from overwhelming context: 200,000 character limit + snapshot/large file prompt specialization</li></ul><h2 id="up-next" tabindex="-1">Up Next <a class="header-anchor" href="#up-next" aria-label="Permalink to &quot;Up Next&quot;">​</a></h2><blockquote><p>Next lesson we&#39;ll cover system capabilities: multi-language/themes/updates/auto-start/HTTP API Server.</p></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Experimental config: compression threshold and switch defaults</td><td><code>src-tauri/src/proxy/config.rs</code></td><td>119-168</td></tr><tr><td>Context estimation: multilingual character estimation + 15% margin</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>9-37</td></tr><tr><td>Token usage estimation: iterate system/messages/tools/thinking</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>103-198</td></tr><tr><td>Layer 1: identify tool rounds + trim old rounds</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>311-439</td></tr><tr><td>Layer 2: Thinking compression while preserving signature (protect last N)</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>200-271</td></tr><tr><td>Layer 3 helper: extract last valid signature</td><td><code>src-tauri/src/proxy/mappers/context_manager.rs</code></td><td>73-109</td></tr><tr><td>Backend task downgrade: Aggressive purification of Thinking blocks</td><td><code>src-tauri/src/proxy/handlers/claude.rs</code></td><td>540-583</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Layer 3: XML summary + Fork session implementation</td><td><code>src-tauri/src/proxy/handlers/claude.rs</code></td><td>1560-1687</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Signature caching: Session signature write/read</td><td><code>src-tauri/src/proxy/signature_cache.rs</code></td><td>141-223</td></tr><tr><td>SSE streaming parsing: cache thinking/tool signature to Session/Tool cache</td><td><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></td><td>766-776</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Request transformation: tool_use prioritize filling signature from Session/Tool cache</td><td><code>src-tauri/src/proxy/mappers/claude/request.rs</code></td><td>1045-1142</td></tr><tr><td>Request transformation: tool_result trigger tool result compression</td><td><code>src-tauri/src/proxy/mappers/claude/request.rs</code></td><td>1159-1225</td></tr><tr><td>Tool result compression: entry <code>compact_tool_result_text()</code></td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>28-69</td></tr><tr><td>Tool result compression: browser snapshot head/tail summary</td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>123-178</td></tr><tr><td>Tool result compression: remove base64 images + total character limit</td><td><code>src-tauri/src/proxy/mappers/tool_result_compressor.rs</code></td><td>247-320</td></tr><tr><td>Test plan: three-tier compression trigger and log verification</td><td><code>docs/testing/context_compression_test_plan.md</code></td><td>1-116</td></tr></tbody></table></details>`,77)])])}const g=t(r,[["render",a]]);export{u as __pageData,g as default};
